INSERT INTO public.community_posts VALUES ('edfe9cd5-e9e2-4b4a-9742-af212b004ed9', '2026 Autumn Intake — Enrolment Deadline April 25', 'Dear Agents, the enrolment deadline for the 2026 Autumn Intake (commencing May 1) is April 25. All student applications must be submitted and documents uploaded before this date. Late submissions may not be processed in time. Please contact your account manager if you need assistance with any pending applications.', 'announcement', 'internal', 'agents', 'b78f9499-7371-437d-b5ff-c294f557d13e', NULL, 'consultant', 'Test Agent Co', true, false, 0, '2026-04-10 10:40:43.759163', '2026-04-10 10:40:43.759163');
INSERT INTO public.community_posts VALUES ('75804e2e-3374-42bc-8de1-57082f88ee74', 'Commission payment tracking — how does it work?', 'Hi team, I can see my commission invoices in the portal but I''m not sure how to read the payment status. Is there a clear indicator showing when payment has been processed vs pending? Also, what is the typical timeframe from invoice approval to actual bank transfer? Any guidance appreciated.', 'question', 'internal', 'agents', 'b78f9499-7371-437d-b5ff-c294f557d13e', NULL, 'consultant', 'Test Agent Co', false, false, 0, '2026-04-12 10:40:43.759163', '2026-04-12 10:40:43.759163');
INSERT INTO public.community_posts VALUES ('2e06fd42-718f-4e5a-9373-41dd3e9713c1', 'Term 2 2026 Class Schedule — Updated', 'BROWNS English Language School has updated the Term 2 2026 timetable. Key changes: General English moved to Room 204, IELTS Preparation now runs Mon-Fri 9am-1pm, Cambridge FCE has a new afternoon session 2pm-5pm. Student briefing materials updated. Please download the latest version from the Documents section.', 'notice', 'internal', 'partners', '632d62d0-ec97-41f9-93b7-eb1e8df595e4', NULL, 'institute', 'BROWNS English Language School', false, false, 0, '2026-04-11 10:40:43.759163', '2026-04-11 10:40:43.759163');
INSERT INTO public.community_posts VALUES ('8088a508-55b3-4d6b-aeb7-507fdd829d78', 'April Welfare Check Reports Due April 30', 'Reminder to all accommodation and guardian partners: Monthly welfare check reports for April 2026 are due by April 30. Please submit reports via the Documents section of each relevant student contract in the portal. Reports must include check-in notes, welfare concerns, and student satisfaction ratings. Contact us for the report template.', 'notice', 'public', 'partners', '632d62d0-ec97-41f9-93b7-eb1e8df595e4', NULL, 'institute', 'BROWNS English Language School', false, false, 0, '2026-04-13 10:40:43.759163', '2026-04-13 10:40:43.759163');
INSERT INTO public.community_posts VALUES ('c0e1f99a-9d21-4a7e-a0f4-07392b3ea8d4', 'Tips for settling into Sydney life — from a student', 'Hi everyone! I arrived 2 weeks ago and here are tips that really helped me: 1) Get an Opal card at the airport for public transport. 2) Download the Transport NSW app for real-time schedules. 3) BROWNS library has free IELTS and Cambridge practice materials. 4) Korean grocery store is 5 minutes walk from school. 5) Ask reception for the student WhatsApp group link. Feel free to ask me anything about life in Sydney!', 'question', 'public', 'all', '1605af17-a158-4315-827c-472d33656a5f', NULL, 'student', 'Ji Young CHOI', false, false, 0, '2026-04-14 10:40:43.759163', '2026-04-14 10:40:43.759163');
INSERT INTO public.community_posts VALUES ('d84695e0-b7e8-4771-b533-cfe054dece74', 'Orientation Day — May 1 New Students Welcome!', 'Welcome to all students starting May 1! Orientation is at BROWNS English Language School, Ground Floor Reception, from 9:00am. Please bring: passport, Confirmation of Enrolment (CoE), and health insurance. The day includes campus tour, library induction, and student handbook. Lunch is provided!', 'announcement', 'public', 'all', '1605af17-a158-4315-827c-472d33656a5f', NULL, 'admin', 'Edubee Team', true, false, 1, '2026-04-09 10:40:43.759163', '2026-04-16 01:11:16.658');
INSERT INTO public.community_comments VALUES ('23940d21-5bb1-4828-b441-fd34257de6d9', 'd84695e0-b7e8-4771-b533-cfe054dece74', '네. 알겠습니다. 확인했습니다.', '1605af17-a158-4315-827c-472d33656a5f', NULL, 'student', 'Ji Young CHOI', false, '2026-04-16 01:11:16.627932', '2026-04-16 01:11:16.627932');
